// Brand Intelligence Extraction
const html = $input.first().json.data || $input.first().json.body || '';

const logoMatch = html.match(/powerplug-logo\.(png|svg|webp)/i);
const logoUrl = logoMatch
  ? `https://powerplug.ai/wp-content/uploads/2022/06/powerplug-logo.${logoMatch[1]}`
  : 'https://powerplug.ai/wp-content/uploads/2022/06/powerplug-logo.png';

const contactMatch = html.match(/href=["'](https?:\/\/powerplug\.ai\/contact[^"']*)["']/i);
const contactUrl = contactMatch ? contactMatch[1] : 'https://powerplug.ai/contact-us';

return [{
  json: {
    brand: {
      name: 'PowerPlug',
      domain: 'powerplug.ai',
      logoUrl: logoUrl,
      homeUrl: 'https://powerplug.ai/home',
      contactUrl: contactUrl,
      colors: {
        primaryNavy: '#131b3b',
        accentGreen: '#8AD628',
        bodyText: '#2a2a2a',
        lightBg: '#f8f9fb',
        altBg: '#fafbfd',
        cardBg: '#ffffff',
        border: '#e2e5ea'
      },
      social: {
        facebook: 'https://www.facebook.com/PowerPlugLtd/',
        twitter: 'https://twitter.com/PowerPlugLtd',
        linkedin: 'https://powerplug.ai/linkedin-insights'
      },
      fontStack: "'Montserrat',-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif",
      tone: 'Enterprise B2B, authoritative, data-driven',
      product: 'PC power management software for enterprises'
    },
    articleConfig: {
      direction: 'ltr',
      language: 'en',
      maxWidth: '820px',
      baseFontSize: '17px',
      lineHeight: '1.8'
    }
  }
}];

// Merge webhook input with brand data
const webhookData = $('Webhook Trigger').first().json.body || $('Webhook Trigger').first().json;
const brandData = $('Extract Brand Intelligence').first().json;
const topic = webhookData.topic || webhookData.keyword || 'IT Cost Reduction';
const targetKeyword = webhookData.targetKeyword || topic;
