// Post-generation validation and cleanup — v3.0
let html = $input.first().json.message?.content || $input.first().json.text || '';
html = html.replace(/^```html?\n?/i, '').replace(/\n?```$/i, '').trim();
const brand = $('Extract Brand Intelligence').first().json.brand;
const errors = [];
const warnings = [];

// CRITICAL CHECKS

// 1. Wrong logo/domain (sentice)
if (html.includes('sentice-author-logo') || html.includes('sentice.com')) {
  errors.push('CRITICAL: Found sentice reference — replacing with PowerPlug assets');
  html = html.replace(/https?:\/\/[^"']*sentice-author-logo[^"']*/gi, brand.logoUrl);
  html = html.replace(/https?:\/\/www\.sentice\.com\/contact/gi, brand.contactUrl);
  html = html.replace(/sentice\.com/gi, 'powerplug.ai');
}

// 2. Logo missing
if (!html.includes('powerplug-logo')) {
  errors.push('CRITICAL: PowerPlug logo missing in author section');
}

// 3. Logo links to home
if (html.includes('powerplug-logo') && !html.match(/href=["']https?:\/\/powerplug\.ai\/home["'][^>]*>.*?<img[^>]*powerplug-logo|powerplug-logo[^>]*>.*?<a[^>]*href=["']https?:\/\/powerplug\.ai\/home["']/s)) {
  // More precise check: verify the author section logo has an anchor wrapping it
  if (html.includes('<a ') && html.includes('powerplug-logo')) {
    const authorSectionMatch = html.match(/<div[^>]*class=[^>]*sa-author[^>]*>([\s\S]*?)<\/div>\s*<div[^>]*class=[^>]*sa-float/s);
    if (authorSectionMatch && !authorSectionMatch[1].includes('powerplug.ai/home')) {
      warnings.push('WARNING: Logo in author section may not link to powerplug.ai/home');
    }
  }
}

// 4. Contact URL missing in CTAs
if (!html.includes(brand.contactUrl)) {
  errors.push('CRITICAL: PowerPlug contact URL not found in CTAs');
}


// 5. TOC numeric prefixes check
const tocNumericPrefix = html.match(/<li[^>]*>\s*\d+[\.\)]\s*<a[^>]*href=/i);
if (tocNumericPrefix) {
  errors.push('CRITICAL: TOC headings contain numeric prefixes — remove all numbering');
}

// 6. FAQ uses details/summary
const detailsCount = (html.match(/<details[^>]*>/gi) || []).length;
const faqDetailsCount = (html.match(/<details[^>]*class=[^>]*sa-faq|class=[^>]*faq-item/gi) || []).length;
if (detailsCount < 2) {
  warnings.push('WARNING: FAQ/TOC may not be using <details>/<summary> properly');
}


// 7. Content block checks (Tip/How-To/Did You Know)
const tipCount = (html.match(/background:#fffbe6|border-left:4px solid #f59e0b/gi) || []).length;
const howtoCount = (html.match(/background:#f0fbe8|border-left:4px solid #8AD628.*How-To|border-left:4px solid #8AD628.*tip/gi) || []).length;
const didyouknowCount = (html.match(/background:#f3f4f6|border-left:4px solid #6366f1/gi) || []).length;
if (tipCount < 1) warnings.push('WARNING: No Tip blocks found — include at least 1 Tip block');
if (howtoCount < 1) warnings.push('WARNING: No How-To blocks found — include at least 1 How-To block');
if (didyouknowCount < 1) warnings.push('WARNING: No Did You Know blocks found — include at least 2');

// 8. H1 count
const h1Count = (html.match(/<h1[^>]*>/gi) || []).length;
if (h1Count === 0) errors.push('CRITICAL: No H1 found in article');
if (h1Count > 1) warnings.push(`WARNING: ${h1Count} H1 tags found — only 1 allowed`);

// 9. Date in hero area check (simple heuristic)
const heroMatch = html.match(/<div[^>]*class=[^>]*sa-hero[\s\S]{0,500}?<\/div>/i);
if (heroMatch && heroMatch[0].match(/\b(January|February|March|April|May|June|July|August|September|October|November|December)\s+\d{4}|\d{4}\s+(January|February|March|April|May|June|July|August|September|October|November|December)/i)) {
  warnings.push('WARNING: Possible date found in hero area — dates belong only in body content');
}

// 10. Section count
const sectionCount = (html.match(/id="section\d+"/g) || []).length;
if (sectionCount < 8) warnings.push(`WARNING: Only ${sectionCount} sections found — aim for 8-12`);


// 11. Brand colors
if (!html.includes(brand.colors.primaryNavy)) warnings.push('WARNING: Primary navy color not found');
if (!html.includes(brand.colors.accentGreen)) warnings.push('WARNING: Accent green color not found');


// 12. Floating buttons on left
if (html.includes('right:') && html.includes('position:fixed')) {
  const floatRight = html.match(/(position:fixed[^;]*right:\s*\d+px)/gi);
  if (floatRight) warnings.push('WARNING: Floating buttons may be on right side — should be on LEFT');
}

// 13. Social hover — CSS :hover preferred over inline JS
const inlineJsHover = (html.match(/onmouseover=|onmouseout=/gi) || []).length;
if (inlineJsHover > 0) {
  warnings.push(`INFO: ${inlineJsHover} social buttons use inline JS hover — CSS :hover preferred but acceptable in WordPress`);
}

// 14. Internal links check
const internalLinks = (html.match(/href=["']https?:\/\/powerplug\.ai[^"']*["']/gi) || []).length;
if (internalLinks < 2) warnings.push('WARNING: Few internal links to powerplug.ai pages found');

// 15. Estimated word count
const estimatedWords = Math.round(html.replace(/<[^>]*>/g, ' ').split(/\s+/).length);

return [{
  json: {
    html: html,
    validation: {
      passed: errors.length === 0,
      errors,
      warnings,
      stats: {
        sectionCount,
        h1Count,
        detailsCount,
        tipBlocks: tipCount,
        howtoBlocks: howtoCount,
        didyouknowBlocks: didyouknowCount,
        internalLinks,
        estimatedWords,
        charCount: html.length,
        correctLogo: html.includes('powerplug-logo'),
        correctContact: html.includes(brand.contactUrl),
        usesNavyColor: html.includes(brand.colors.primaryNavy),
        usesGreenAccent: html.includes(brand.colors.accentGreen)
      }
    }
  }
}];

// Dynamic system prompt builder — v3.0
// Embeds the full v3.0 Improved_N8N_Prompt.txt ruleset
const brandData = $('Extract Brand Intelligence').first().json;
const systemPrompt = `You are a senior B2B content strategist and frontend engineer producing enterprise-grade long-form articles for PowerPlug.ai.

BRAND IDENTITY:
- Company: PowerPlug (https://powerplug.ai)
- Logo: ${brandData.brand.logoUrl} — use ONLY this logo
- Home URL: ${brandData.brand.homeUrl}
- Contact URL: ${brandData.brand.contactUrl} — link ALL CTAs here
- Colors: Navy ${brandData.brand.colors.primaryNavy}, Green ${brandData.brand.colors.accentGreen}
- Font: ${brandData.brand.fontStack}
- Social: Facebook ${brandData.brand.social.facebook}, Twitter ${brandData.brand.social.twitter}, LinkedIn ${brandData.brand.social.linkedin}


CRITICAL RULES:
1. Use ONLY the PowerPlug logo URL in the About the Author section
2. Logo in author section MUST link to ${brandData.brand.homeUrl}
3. ALL CTA buttons link to ${brandData.brand.contactUrl}
4. Use <details>/<summary> for TOC and FAQ — NO JavaScript onclick buttons
5. TOC headings: NO numeric prefixes (write "Section Name", not "1. Section Name")
6. Inline CSS only (one <style> block allowed for ::after indicators, :hover, @media)
7. Direction: LTR, Language: English
8. Floating buttons on LEFT side only
9. Tip blocks: background #fffbe6, border-left 4px solid #f59e0b
10. How-To blocks: background #f0fbe8, border-left 4px solid #8AD628
11. Did You Know blocks: background #f3f4f6, border-left 4px solid #6366f1
12. Mid-article inline conversion nudges between sections
13. Social hover colors: Facebook=#1877F2, Twitter=#000, LinkedIn=#0A66C2
14. NEVER fabricate statistics or link to non-existent pages
15. NEVER use sentice.com — PowerPlug is the brand, powerplug.ai is the domain
16. Exactly ONE H1 in the hero section
17. NO dates in the hero area or first paragraph
18. About the Author section is the LAST content block before floating buttons

OUTPUT: Complete HTML article ready for WordPress. No markdown, no explanation.`;
return [{ json: { systemPrompt } }];
